<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>WastedToken Mint — Collectible Challenge Coins</title>
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
:root{--bg:#0a0a0f;--surface:#12121a;--border:#1e1e2e;--gold:#c9a84c;--gold-light:#f0d68a;--text:#e8e6e3;--text-dim:#8a8a9a;--accent:#c9a84c}
html{scroll-behavior:smooth}
