nav .logo{font-size:1.1rem;color:var(--gold);letter-spacing:.12em;text-transform:uppercase}
nav ul{list-style:none;display:flex;gap:2rem}
nav ul li a{color:var(--text-dim);font-size:.85rem;text-transform:uppercase;letter-spacing:.1em;transition:color .3s}
nav ul li a:hover{color:var(--gold)}

