#hero{position:relative;width:100%;height:100vh;display:flex;align-items:center;justify-content:center;overflow:hidden;background:radial-gradient(ellipse at 50% 40%,#1a1a2e 0%,#0a0a0f 70%)}
#coin-hero{display:block}
.hero-title{position:absolute;bottom:8%;left:50%;transform:translateX(-50%);text-align:center;pointer-events:none}
.hero-title h1{font-size:clamp(1.8rem,4vw,3.2rem);color:var(--gold);text-transform:uppercase;letter-spacing:.15em;margin-bottom:.3rem;text-shadow:0 0 40px rgba(201,168,76,.3)}
.hero-title p{font-size:clamp(.8rem,1.5vw,1.1rem);color:var(--text-dim);letter-spacing:.2em;text-transform:uppercase}

/* ABOUT */
#about{max-width:900px;margin:0 auto;padding:6rem 2rem;text-align:center}
