.edition:hover{transform:translateY(-4px);border-color:var(--gold)}
.edition canvas{display:block;margin:0 auto 1rem;border-radius:8px}
.edition h3{font-size:1.1rem;color:var(--text);margin-bottom:.3rem;letter-spacing:.08em}
.edition .edition-desc{font-size:.85rem;color:var(--text-dim);margin-bottom:1rem}
.edition .status{font-size:.75rem;text-transform:uppercase;letter-spacing:.15em;padding:.3rem .8rem;border-radius:4px;display:inline-block;margin-bottom:1rem}
