CoinRenderer.prototype.render=function(t){
  var gl=this.gl;
  if(!gl)return;

  gl.viewport(0,0,this.canvas.width,this.canvas.height);
  gl.clearColor(this.bgColor[0],this.bgColor[1],this.bgColor[2],1);
  gl.clear(gl.COLOR_BUFFER_BIT|gl.DEPTH_BUFFER_BIT);

  gl.useProgram(this.program);

  // Camera
  var aspect=this.canvas.width/this.canvas.height;
  var proj=mat4Perspective(Math.PI/4,aspect,0.5,10);
  var eye=[0,0,2.2];
  var view=mat4LookAt(eye,[0,0,0],[0,1,0]);
  var vp=mat4Multiply(proj,view);

  // Rotation: Y-axis continuous, X-axis flip
  var yAngle=t*Math.PI*2; // full rotation around Y
  var xAngle=Math.sin(t*Math.PI)*Math.PI*0.85; // flip to show both faces

  var model=mat4Multiply(mat4RotY(yAngle),mat4RotX(xAngle));
  var mvp=mat4Multiply(vp,model);
  var normMat=mat3FromMat4(model);

  gl.uniformMatrix4fv(this.uMVP,false,mvp);
  gl.uniformMatrix4fv(this.uModel,false,model);
  gl.uniformMatrix3fv(this.uNormMat,false,normMat);
  gl.uniform3f(this.uLightDir,0.5,0.8,0.6);
  gl.uniform3f(this.uEyePos,eye[0],eye[1],eye[2]);
  gl.uniform3f(this.uMetalColor,this.frontColor[0],this.frontColor[1],this.frontColor[2]);
  gl.uniform1f(this.uMetalness,0.92);
  gl.uniform1f(this.uRoughness,0.18);
  gl.uniform1f(this.uFace,0.5);
  gl.uniform1f(this.uTime,t);

  // Bind textures
  gl.activeTexture(gl.TEXTURE0);
  gl.bindTexture(gl.TEXTURE_2D,this.frontTex);
  gl.uniform1i(this.uFrontTex,0);
  gl.activeTexture(gl.TEXTURE1);
  gl.bindTexture(gl.TEXTURE_2D,this.backTex);
  gl.uniform1i(this.uBackTex,1);

  // Bind attributes
  gl.bindBuffer(gl.ARRAY_BUFFER,this.vboPos);
  gl.enableVertexAttribArray(this.aPos);
  gl.vertexAttribPointer(this.aPos,3,gl.FLOAT,false,0,0);

  gl.bindBuffer(gl.ARRAY_BUFFER,this.vboNorm);
  gl.enableVertexAttribArray(this.aNorm);
  gl.vertexAttribPointer(this.aNorm,3,gl.FLOAT,false,0,0);

  gl.bindBuffer(gl.ARRAY_BUFFER,this.vboUV);
  gl.enableVertexAttribArray(this.aUV);
  gl.vertexAttribPointer(this.aUV,2,gl.FLOAT,false,0,0);

  gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER,this.ibo);
  gl.drawElements(gl.TRIANGLES,this.indexCount,gl.UNSIGNED_SHORT,0);
};

